### 9. `/private/tmp/claude-eval-v4-20260227-234754/none/src/test/kotlin/com/maum/app/domain/user/service/UserServiceTest.kt`

```kotlin
package com.maum.app.domain.user.service

import com.maum.app.domain.user.entity.Follow
import com.maum.app.domain.user.entity.User
import com.maum.app.domain.user.exception.AlreadyFollowingException
import com.maum.app.domain.user.exception.SelfFollowException
import com.maum.app.domain.user.exception.UserNotFoundException
import com.maum.app.domain.user.repository.FollowRepository
import com.maum.app.domain.user.repository.UserRepository
import org.assertj.core.api.Assertions.assertThat
import org.assertj.core.api.Assertions.assertThatThrownBy
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.ArgumentCaptor
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.capture
import org.mockito.kotlin.verify
import org.mockito.kotlin.whenever
import java.util.Optional

@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ────────────────────────────────────────────────────────
    // follow()
    // ────────────────────────────────────────────────────────

    @Test
    fun `follow 성공 시 Follow 엔티티를 저장하고 반환한다`() {
        // given
        val follower = User(id = 1L, username = "alice", email = "alice@maum.com")
        val followee = User(id = 2L, username = "bob", email = "bob@maum.com")
        val savedFollow = Follow(id = 10L, follower = follower, followee = followee)

        whenever(userRepository.findById(1L)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(2L)).thenReturn(Optional.of(followee))
        whenever(followRepository.existsByFollowerIdAndFolloweeId(1L, 2L)).thenReturn(false)
        whenever(followRepository.save(any())).thenReturn(savedFollow)

        // when
        val result = userService.follow(followerId = 1L, followeeId = 2L)

        // then
        assertThat(result.id).isEqualTo(10L)
        assertThat(result.follower.id).isEqualTo(1L)
        assertThat(result.followee.id).isEqualTo(2L)

        val captor = ArgumentCaptor.forClass(Follow::class.java)
        verify(followRepository).save(capture(captor))
        assertThat(captor.value.follower).isEqualTo(follower)
        assertThat(captor.value.followee).isEqualTo(followee)
    }

    @Test
    fun `자기 자신을 팔로우하면 SelfFollowException을 던진다`() {
        // given
        val userId = 1L

        // when & then
        assertThrows<SelfFollowException> {
            userService.follow(followerId = userId, followeeId = userId)
        }
    }

    @Test
    fun `팔로워(followerId)가 존재하지 않으면 UserNotFoundException을 던진다`() {
        // given
        whenever(userRepository.findById(999L)).thenReturn(Optional.empty())
        whenever(userRepository.findById(2L)).thenReturn(
            Optional.of(User(id = 2L, username = "bob", email = "bob@maum.com"))
        )

        // when & then
        assertThatThrownBy {
            userService.follow(followerId = 999L, followeeId = 2L)
        }.isInstanceOf(UserNotFoundException::class.java)
            .hasMessageContaining("999")
    }

    @Test
    fun `팔로위(followeeId)가 존재하지 않으면 UserNotFoundException을 던진다`() {
        // given
        val follower = User(id = 1L, username = "alice", email = "alice@maum.com")
        whenever(userRepository.findById(1L)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(999L)).thenReturn(Optional.empty())

        // when & then
        assertThatThrownBy {
            userService.follow(followerId = 1L, followeeId = 999L)
        }.isInstanceOf(UserNotFoundException::class.java)
            .hasMessageContaining("999")
    }

    @Test
    fun `이미 팔로우 중이면 AlreadyFollowingException을 던진다`() {
        // given
        val follower = User(id = 1L, username = "alice", email = "alice@maum.com")
        val followee = User(id = 2L, username = "bob", email = "bob@maum.com")

        whenever(userRepository.findById(1L)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(2L)).thenReturn(Optional.of(followee))
        whenever(followRepository.existsByFollowerIdAndFolloweeId(1L, 2L)).thenReturn(true)

        // when & then
        assertThrows<AlreadyFollowingException> {
            userService.follow(followerId = 1L, followeeId = 2L)
        }
    }

    // ────────────────────────────────────────────────────────
    // unfollow()
    // ────────────────────────────────────────────────────────

    @Test
    fun `unfollow 성공 시 Follow를 삭제한다`() {
        // given
        whenever(followRepository.existsByFollowerIdAndFolloweeId(1L, 2L)).thenReturn(true)

        // when
        userService.unfollow(followerId = 1L, followeeId = 2L)

        // then
        verify(followRepository).deleteByFollowerIdAndFolloweeId(1L, 2L)
    }

    @Test
    fun `팔로우 관계가 없으면 IllegalStateException을 던진다`() {
        // given
        whenever(followRepository.existsByFollowerIdAndFolloweeId(1L, 2L)).thenReturn(false)

        // when & then
        assertThatThrownBy {
            userService.unfollow(followerId = 1L, followeeId = 2L)
        }.isInstanceOf(IllegalStateException::class.java)
            .hasMessage("팔로우 관계가 존재하지 않습니다")
    }

    // ────────────────────────────────────────────────────────
    // getFollowers()
    // ────────────────────────────────────────────────────────

    @Test
    fun `팔로워 목록을 반환한다`() {
        // given
        val targetUser = User(id = 2L, username = "bob", email = "bob@maum.com")
        val followerA = User(id = 1L, username = "alice", email = "alice@maum.com")
        val followerC = User(id = 3L, username = "carol", email = "carol@maum.com")

        val follows = listOf(
            Follow(id = 10L, follower = followerA, followee = targetUser),
            Follow(id = 11L, follower = followerC, followee = targetUser),
        )

        whenever(userRepository.existsById(2L)).thenReturn(true)
        whenever(followRepository.findByFolloweeId(2L)).thenReturn(follows)

        // when
        val result = userService.getFollowers(userId = 2L)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.username }).containsExactlyInAnyOrder("alice", "carol")
        verify(followRepository).findByFolloweeId(2L)
    }

    @Test
    fun `존재하지 않는 사용자의 팔로워 조회 시 UserNotFoundException을 던진다`() {
        // given
        whenever(userRepository.existsById(999L)).thenReturn(false)

        // when & then
        assertThatThrownBy {
            userService.getFollowers(userId = 999L)
        }.isInstanceOf(UserNotFoundException::class.java)
            .hasMessageContaining("999")
    }

    // ────────────────────────────────────────────────────────
    // getFollowings()
    // ────────────────────────────────────────────────────────

    @Test
    fun `팔로잉 목록을 반환한다`() {
        // given
        val sourceUser = User(id = 1L, username = "alice", email = "alice@maum.com")
        val followeeB = User(id = 2L, username = "bob", email = "bob@maum.com")
        val followeeC = User(id = 3L, username = "carol", email = "carol@maum.com")

        val follows = listOf(
            Follow(id = 10L, follower = sourceUser, followee = followeeB),
            Follow(id = 11L, follower = sourceUser, followee = followeeC),
        )

        whenever(userRepository.existsById(1L)).thenReturn(true)
        whenever(followRepository.findByFollowerId(1L)).thenReturn(follows)

        // when
        val result = userService.getFollowings(userId = 1L)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.username }).containsExactlyInAnyOrder("bob", "carol")
        verify(followRepository).findByFollowerId(1L)
    }

    @Test
    fun `존재하지 않는 사용자의 팔로잉 조회 시 UserNotFoundException을 던진다`() {
        // given
        whenever(userRepository.existsById(999L)).thenReturn(false)

        // when & then
        assertThatThrownBy {
            userService.getFollowings(userId = 999L)
        }.isInstanceOf(UserNotFoundException::class.java)
            .hasMessageContaining("999")
    }
}
```

