### Service

**`src/main/kotlin/com/maum/app/domain/user/service/UserService.kt`**
```kotlin
package com.maum.app.domain.user.service

import com.maum.app.domain.user.entity.Follow
import com.maum.app.domain.user.entity.User
import com.maum.app.domain.user.exception.AlreadyFollowingException
import com.maum.app.domain.user.exception.SelfFollowException
import com.maum.app.domain.user.exception.UserNotFoundException
import com.maum.app.domain.user.repository.FollowRepository
import com.maum.app.domain.user.repository.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {
    @Transactional
    fun follow(followerId: Long, followeeId: Long): Follow {
        if (followerId == followeeId) throw SelfFollowException(followerId)

        val follower = userRepository.findById(followerId)
            .orElseThrow { UserNotFoundException(followerId) }
        val followee = userRepository.findById(followeeId)
            .orElseThrow { UserNotFoundException(followeeId) }

        if (followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            throw AlreadyFollowingException(followerId, followeeId)

        return followRepository.save(Follow(follower = follower, followee = followee))
    }

    @Transactional
    fun unfollow(followerId: Long, followeeId: Long) {
        if (!followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            throw IllegalStateException("팔로우 관계가 존재하지 않습니다")
        followRepository.deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Transactional(readOnly = true)
    fun getFollowers(userId: Long): List<User> {
        if (!userRepository.existsById(userId)) throw UserNotFoundException(userId)
        return followRepository.findByFolloweeId(userId).map { it.follower }
    }

    @Transactional(readOnly = true)
    fun getFollowings(userId: Long): List<User> {
        if (!userRepository.existsById(userId)) throw UserNotFoundException(userId)
        return followRepository.findByFollowerId(userId).map { it.followee }
    }
}
